  const calendarEvents = state.google.connected ? state.google.events.map(event => ({ id: event.id, time: new Date(event.start.dateTime || `${event.start.date}T00:00:00`).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }), end: new Date(event.end.dateTime || `${event.end.date}T00:00:00`).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }), title: event.summary || '(Untitled event)', type: 'meeting' })) : events;
