       <section class="panel compact spotify ${state.visibility.spotify === false ? 'hidden-by-preference' : ''}"><header><div><p class="eyebrow">SPOTIFY</p><h2>${spotify.connected ? 'Listening data' : 'Listening now'}</h2></div>${badge(spotify.connected ? 'connected' : 'estimated', spotify.connected ? 'exact' : 'estimated')}</header><div class="track"><div class="album">◒</div><p><strong>${escape(currentTrack.title)}</strong><small>${escape(currentTrack.artist)} · ${currentTrack.duration} min</small></p><button class="icon-button" data-action="connect-spotify">${spotify.connected ? '↻' : '↗'}</button></div><div class="artists"><span>TOP TODAY</span>${topArtists.map(a => `<b>${escape(a)}</b>`).join('')}</div><footer><button class="text-button" data-action="connect-spotify">${spotify.connected ? 'Reconnect Spotify' : 'Connect Spotify'}</button></footer></section>
