  if(action === 'save-tested-notion') { const setup = window.notionDiagnostic; if (!setup) return toast('Reopen Notion setup and test the connection again.'); document.querySelector('#modal').close(); configureNotion(setup.token, setup.parentId, setup.property).then(() => toast('Notion configured locally.')).catch(error => toast(error.message)); }
